wab_tbl <- wab_data |> 
  dplyr::filter(game_type == "played", wab > 0.60) |> 
    cbbplotR::gt_cbb_teams(team, team, logo_height = 20, include_name = FALSE) |> 
  cbbplotR::gt_cbb_teams(opp, opp, logo_height = 20, include_name = FALSE) |>
  dplyr::mutate(
    winner_score = stringr::str_split_i(score, "-", 1),
    loser_score = stringr::str_split_i(score, "-", 2),
    wab_range = dplyr::case_when(
      wab >= 0.90 ~ "0.90+ and up",
      wab >= 0.85 ~ "0.85 to 0.90",
      wab >= 0.80 ~ "0.80 to 0.85",
      wab >= 0.75 ~ "0.75 to 0.80",
      wab >= 0.70 ~ "0.70 to 0.75",
      wab >= 0.65 ~ "0.65 to 0.70",
      wab >= 0.60 ~ "0.60 to 0.65"
    ),
    wab_range = factor(wab_range, levels = c(
      "0.90+ and up", "0.85 to 0.90", "0.80 to 0.85", "0.75 to 0.80", 
      "0.70 to 0.75", "0.65 to 0.70", "0.60 to 0.65"
    )),
    location_full = dplyr::case_when(
      location == "A" ~ "Away",
      location == "H" ~ "Home",
      location == "N" ~ "Neutral"
    ),
    wab_display = sprintf("%.2f", wab)
  ) |> 
  dplyr::arrange(-wab) |> 
  dplyr::group_by(wab_range, location_full) |> 
  dplyr::mutate(
    game_num = dplyr::row_number(),
    game_result = paste0("**+", wab_display, "**", " | ", team, " ", winner_score, "-", loser_score, " ", opp)
  ) |> 
  dplyr::summarise(
    games = paste(game_result, collapse = "  \n"),
    .groups = "drop"
  ) |> 
    tidyr::pivot_wider(names_from = location_full, values_from = games, values_fill = "") |> 
  dplyr::mutate(
    Away = dplyr::na_if(Away, ""),
    Home = dplyr::na_if(Home, ""),
    Neutral = dplyr::na_if(Neutral, "")
  ) |>
  dplyr::select(WAB = wab_range, Away, Home, Neutral) |> 
    dplyr::ungroup() |> 
  gt::gt() |> 
  gtUtils::gt_theme_savant() |>  
  gt::fmt_markdown(columns = c(Away, Home, Neutral)) |> 
  gt::sub_missing(columns = c(Away, Home, Neutral), missing_text = "") |> 
  gt::cols_align(align = "left", columns = c(Away, Home, Neutral)) |> 
  gt_column_subheaders(
      WAB = list(heading = "WAB", subtitle = "Wins-Above-Bubble"),
      Away = list(heading = "Road Wins", subtitle = "35 total games"),
      Home = list(heading = "Home Wins", subtitle = "8 total games"),
      Neutral = list(heading = "Neutral Site Wins", subtitle = "28 total games")
  ) |> 
  gt::tab_header(title = gt::html(wab_header)) |> 
  gt::tab_source_note(
    source_note =
      gt::html(
        "<hr>Data via barttorvik.com and WAB values calculated via Torvik ratings | theme via {gtUtils} <br>
        Winning games on the road is useful to building a resume!<br>
        Data only for games played before January 6, 2026<br>
        <hr><b>Table by Chris at Bless your chart</b>"
      )
  ) |>
  gt::tab_style(
    style = list(gt::cell_borders(
      sides = c("left", "right", "top", "bottom"),
      color = "black",
      weight = gt::px(2)
    )),
    locations = list(
      gt::cells_body(),
      gt::cells_column_labels(),
      gt::cells_row_groups()
    )
  ) |> 
  gtUtils::gt_border_bars_bottom(c("#0d1e2d", "#c1d6e2",
                                   "#f07e1d")) |> 
  gt::tab_options(table.width = gt::px(625)) |> 
